  9→/// Batch size per animation frame tick
 10→const BATCH_SIZE: u64 = 50_000;
 11→
 12→pub enum Msg {
 13→    /// Initialize: assemble and load the interpreter binary
 14→    Init,
 15→    /// Run a batch of CPU instructions
 16→    Tick,
 17→    /// User typed in the input area
 18→    InputChanged(String),
 19→    /// User clicked Eval (send input to UART)
 20→    Eval,
 21→}
 22→
 23→pub struct Repl {
 24→    emulator: EmulatorCore,
 25→    output: String,
 26→    input: String,
 27→    status: String,
 28→    running: bool,
 29→    loaded: bool,
 30→    input_ref: NodeRef,
 31→}
 32→
 33→impl Component for Repl {
 34→    type Message = Msg;
 35→    type Properties = ();
 36→
 37→    fn create(ctx: &Context<Self>) -> Self {
 38→        // Trigger init on next tick
 39→        ctx.link().send_message(Msg::Init);
 40→
 41→        Self {
 42→            emulator: EmulatorCore::new(),
 43→            output: String::new(),
 44→            input: String::from("(+ 1 2)"),
 45→            status: "Assembling interpreter...".into(),
 46→            running: false,
 47→            loaded: false,
 48→            input_ref: NodeRef::default(),
 49→        }
 50→    }
 51→
 52→    fn update(&mut self, ctx: &Context<Self>, msg: Self::Message) -> bool {
 53→        match msg {
 54→            Msg::Init => {
 55→                let mut asm = Assembler::new();
 56→                let result = asm.assemble(TML24C_ASM);
 57→
 58→                if !result.errors.is_empty() {
 59→                    self.status = format!("Assembly failed: {}", result.errors[0]);
 60→                    return true;
 61→                }
 62→
 63→                // Load assembled binary into emulator
 64→                self.emulator.hard_reset();
 65→                for (addr, &byte) in result.bytes.iter().enumerate() {
 66→                    self.emulator.write_byte(addr as u32, byte);
 67→                }
 68→                self.emulator.set_pc(0);
 69→
 70→                self.status = format!(
 71→                    "Loaded {} bytes. Running interpreter tests...",
 72→                    result.bytes.len()
 73→                );
 74→                self.loaded = true;
 75→
 76→                // Start running the interpreter (it runs tests on startup)
 77→                self.emulator.resume();
 78→                self.running = true;
 79→                ctx.link().send_message(Msg::Tick);
 80→                true
 81→            }
 82→
 83→            Msg::Tick => {
 84→                if !self.running {
 85→                    return false;
 86→                }
 87→
 88→                let result = self.emulator.run_batch(BATCH_SIZE);
 89→
 90→                // Capture UART output
 91→                let uart = self.emulator.get_uart_output().to_string();
 92→                if uart != self.output {
 93→                    self.output = uart;
 94→                }
 95→
 96→                match result.reason {
 97→                    StopReason::CycleLimit => {
 98→                        // More work to do — schedule next tick
 99→                        let link = ctx.link().clone();
100→                        Timeout::new(0, move || link.send_message(Msg::Tick)).forget();
101→                        self.status = format!(
102→                            "Running... {} instructions",
103→                            self.emulator.instructions_count()
104→                        );
105→                    }
106→                    StopReason::Halted => {
107→                        self.running = false;
108→                        self.status = format!(
109→                            "Halted after {} instructions. Ready.",
110→                            self.emulator.instructions_count()
111→                        );
112→                    }
113→                    StopReason::InvalidInstruction(byte) => {
114→                        self.running = false;
115→                        self.status = format!(
116→                            "Invalid instruction 0x{:02X} at PC=0x{:06X}",
117→                            byte,
118→                            self.emulator.pc()
119→                        );
120→                    }
121→                    StopReason::Breakpoint(addr) => {
122→                        self.running = false;
123→                        self.status = format!("Breakpoint at 0x{:06X}", addr);
124→                    }
125→                    StopReason::Paused => {
126→                        self.running = false;
127→                        self.status = "Paused.".into();
128→                    }
129→                }
130→                true
131→            }
132→
133→            Msg::InputChanged(value) => {
134→                self.input = value;
135→                false
136→            }
137→
138→            Msg::Eval => {
139→                if !self.loaded {
140→                    self.status = "Interpreter not loaded yet.".into();
141→                    return true;
142→                }
143→
144→                // Send input text to UART byte-by-byte
145→                for byte in self.input.bytes() {
146→                    self.emulator.send_uart_byte(byte);
147→                }
148→                // Send newline to terminate input
149→                self.emulator.send_uart_byte(b'\n');
150→
151→                self.status = "Evaluating...".into();
152→                self.emulator.resume();
153→                self.running = true;
154→                ctx.link().send_message(Msg::Tick);
155→                true
156→            }
157→        }
158→    }
159→
160→    fn view(&self, ctx: &Context<Self>) -> Html {
161→        let on_input = ctx.link().callback(|e: InputEvent| {
162→            let target: HtmlTextAreaElement = e.target_unchecked_into();
163→            Msg::InputChanged(target.value())
164→        });
165→
166→        let on_eval = ctx.link().callback(|_| Msg::Eval);
167→
168→        html! {
169→            <div class="repl">
