183→                    />
184→                    <div class="controls">
185→                        <button onclick={on_eval} disabled={self.running || !self.loaded}>
186→                            {"Eval"}
187→                        </button>
188→                        <span class="status">{ &self.status }</span>
189→                    </div>
190→                </div>
191→
192→                <style>{r#"
193→                    .repl {
194→                        display: flex;
195→                        flex-direction: column;
196→                        flex: 1;
197→                        overflow: hidden;
198→                        padding: 12px 20px;
199→                        gap: 12px;
200→                    }
201→                    .panel-header {
202→                        font-size: 11px;
203→                        text-transform: uppercase;
204→                        letter-spacing: 0.1em;
205→                        color: var(--dim);
206→                        margin-bottom: 6px;
207→                    }
