209→                        flex: 1;
210→                        display: flex;
211→                        flex-direction: column;
212→                        min-height: 0;
213→                    }
214→                    .output {
215→                        flex: 1;
216→                        background: var(--surface);
217→                        border: 1px solid var(--border);
218→                        border-radius: 6px;
219→                        padding: 12px;
