 12→void test_scaffold() {
 13→    /* Fixnum */
 14→    puts_str("fixnum 42 = ");
 15→    print_val(MAKE_FIXNUM(42));
 16→    putc_uart(10);
 17→
 18→    /* Symbols */
 19→    puts_str("nil = ");
 20→    print_val(NIL_VAL);
 21→    putc_uart(10);
 22→
 23→    puts_str("t = ");
 24→    print_val(T_VAL);
 25→    putc_uart(10);
 26→
 27→    int foo = intern("foo");
 28→    puts_str("foo = ");
 29→    print_val(foo);
 30→    putc_uart(10);
 31→
 32→    /* Cons pair */
 33→    int pair = cons(MAKE_FIXNUM(1), MAKE_FIXNUM(2));
 34→    puts_str("(1 . 2) = ");
 35→    print_val(pair);
 36→    putc_uart(10);
 37→
 38→    /* List (a b c) */
 39→    int sa = intern("a");
 40→    int sb = intern("b");
 41→    int sc = intern("c");
 42→    int lst = cons(sa, cons(sb, cons(sc, NIL_VAL)));
 43→    puts_str("(a b c) = ");
 44→    print_val(lst);
 45→    putc_uart(10);
 46→
 47→    /* Nested list (1 (2 3)) */
 48→    int inner = cons(MAKE_FIXNUM(2), cons(MAKE_FIXNUM(3), NIL_VAL));
 49→    int nested = cons(MAKE_FIXNUM(1), cons(inner, NIL_VAL));
 50→    puts_str("(1 (2 3)) = ");
 51→    print_val(nested);
 52→    putc_uart(10);
 53→
 54→    puts_str("scaffold ok\n");
 55→}
