  9→ *   - Quote shorthand: 'x -> (quote x)
 10→ */
 11→
 12→char *read_ptr;
 13→
 14→int is_whitespace(int ch) {
 15→    return ch == ' ' || ch == '\n' || ch == '\t' || ch == '\r';
 16→}
 17→
 18→int is_digit(int ch) {
 19→    return ch >= '0' && ch <= '9';
 20→}
 21→
 22→int is_sym_char(int ch) {
 23→    if (ch == 0) return 0;
 24→    if (is_whitespace(ch)) return 0;
 25→    if (ch == '(' || ch == ')' || ch == '\'') return 0;
 26→    if (ch == '.') return 0;
 27→    return 1;
 28→}
 29→
 30→void skip_whitespace() {
 31→    while (is_whitespace(*read_ptr)) {
 32→        read_ptr = read_ptr + 1;
 33→    }
 34→}
 35→
 36→int read_expr();
 37→
 38→int read_int() {
 39→    int neg = 0;
 40→    if (*read_ptr == '-') {
 41→        neg = 1;
 42→        read_ptr = read_ptr + 1;
 43→    }
 44→    int n = 0;
 45→    while (is_digit(*read_ptr)) {
 46→        n = n * 10 + (*read_ptr - '0');
 47→        read_ptr = read_ptr + 1;
 48→    }
 49→    if (neg) n = 0 - n;
 50→    return MAKE_FIXNUM(n);
 51→}
 52→
 53→int read_symbol() {
 54→    char buf[64];
 55→    int i = 0;
 56→    while (is_sym_char(*read_ptr) && i < 63) {
 57→        buf[i] = *read_ptr;
 58→        i = i + 1;
 59→        read_ptr = read_ptr + 1;
 60→    }
 61→    buf[i] = 0;
 62→    return intern(buf);
 63→}
 64→
 65→int read_list() {
 66→    /* skip opening '(' */
 67→    read_ptr = read_ptr + 1;
 68→    skip_whitespace();
 69→
 70→    if (*read_ptr == ')') {
 71→        read_ptr = read_ptr + 1;
 72→        return NIL_VAL;
 73→    }
 74→
 75→    /* read first element */
 76→    int first = read_expr();
 77→    skip_whitespace();
 78→
 79→    /* check for dotted pair */
 80→    if (*read_ptr == '.') {
 81→        read_ptr = read_ptr + 1;
 82→        skip_whitespace();
 83→        int d = read_expr();
 84→        skip_whitespace();
 85→        if (*read_ptr == ')') {
 86→            read_ptr = read_ptr + 1;
 87→        }
 88→        return cons(first, d);
 89→    }
 90→
 91→    /* build list */
 92→    int head = cons(first, NIL_VAL);
 93→    int tail = head;
 94→    while (*read_ptr && *read_ptr != ')') {
 95→        int elem = read_expr();
 96→        skip_whitespace();
 97→
 98→        /* check for dot after element */
 99→        if (*read_ptr == '.') {
100→            read_ptr = read_ptr + 1;
101→            skip_whitespace();
102→            int d = read_expr();
103→            skip_whitespace();
104→            heap_cdr[PTR_IDX(tail)] = d;
105→            if (*read_ptr == ')') {
106→                read_ptr = read_ptr + 1;
107→            }
108→            return head;
109→        }
110→
111→        int cell = cons(elem, NIL_VAL);
112→        heap_cdr[PTR_IDX(tail)] = cell;
113→        tail = cell;
114→    }
115→
116→    if (*read_ptr == ')') {
117→        read_ptr = read_ptr + 1;
118→    }
119→    return head;
120→}
121→
122→int read_expr() {
123→    skip_whitespace();
124→
125→    int ch = *read_ptr;
126→
127→    if (ch == '(') {
128→        return read_list();
129→    }
130→
131→    if (ch == '\'') {
132→        read_ptr = read_ptr + 1;
133→        int val = read_expr();
134→        int quote_sym = intern("quote");
135→        return cons(quote_sym, cons(val, NIL_VAL));
136→    }
137→
138→    /* negative number: '-' followed by digit */
139→    if (ch == '-' && is_digit(*(read_ptr + 1))) {
140→        return read_int();
141→    }
142→
143→    if (is_digit(ch)) {
144→        return read_int();
145→    }
146→
147→    /* symbol */
148→    if (ch != 0 && ch != ')') {
149→        return read_symbol();
150→    }
151→
152→    return NIL_VAL;
153→}
154→
155→int read_str(char *input) {
156→    read_ptr = input;
157→    return read_expr();
158→}
159→

150→    if (id == PRIM_LT) {
151→        if (FIXNUM_VAL(a) < FIXNUM_VAL(b)) return T_VAL;
152→        return NIL_VAL;
153→    }
154→    if (id == PRIM_EQ_NUM) {
155→        if (FIXNUM_VAL(a) == FIXNUM_VAL(b)) return T_VAL;
156→        return NIL_VAL;
157→    }
158→    if (id == PRIM_CONS) return cons(a, b);
159→    if (id == PRIM_CAR) return car(a);
160→    if (id == PRIM_CDR) return cdr(a);
161→    if (id == PRIM_LIST) return args;
162→    if (id == PRIM_NULLP) {
163→        if (IS_NIL(a)) return T_VAL;
164→        return NIL_VAL;
165→    }
166→    if (id == PRIM_PAIRP) {
167→        if (IS_CONS(a)) return T_VAL;
168→        return NIL_VAL;
169→    }
170→    if (id == PRIM_ATOMP) {
171→        if (!IS_CONS(a)) return T_VAL;
172→        return NIL_VAL;
173→    }
174→    if (id == PRIM_EQP) {
175→        if (a == b) return T_VAL;
176→        return NIL_VAL;
177→    }
178→    if (id == PRIM_NOT) {
179→        if (IS_NIL(a)) return T_VAL;
180→        return NIL_VAL;
181→    }
182→    if (id == PRIM_PRINT) {
183→        print_val(a);
184→        return a;
185→    }
186→    if (id == PRIM_NUMP) {
187→        if (IS_FIXNUM(a)) return T_VAL;
188→        return NIL_VAL;
189→    }
190→
191→    return NIL_VAL;
192→}
193→
194→int eval(int expr, int env) {
195→    /* Self-evaluating */
196→    if (IS_FIXNUM(expr)) return expr;
197→    if (IS_NIL(expr)) return expr;
198→    if (expr == T_VAL) return expr;
199→    if (IS_EXTENDED(expr)) return expr;
200→
201→    /* Symbol lookup */
202→    if (IS_SYMBOL(expr)) {
203→        return env_lookup(expr, env);
204→    }
205→
206→    /* List: special form or function call */
207→    if (!IS_CONS(expr)) return expr;
208→
209→    int head = car(expr);
210→    int args = cdr(expr);
211→
212→    /* quote */
213→    if (head == sym_quote) {
214→        return car(args);
215→    }
216→
217→    /* if */
218→    if (head == sym_if) {
219→        int cond_val = eval(car(args), env);
220→        if (!IS_NIL(cond_val)) {
221→            return eval(car(cdr(args)), env);
222→        }
223→        int else_part = cdr(cdr(args));
224→        if (IS_NIL(else_part)) return NIL_VAL;
225→        return eval(car(else_part), env);
226→    }
227→
228→    /* define */
229→    if (head == sym_define) {
230→        int sym = car(args);
231→        int val = eval(car(cdr(args)), env);
232→        global_env = env_extend(sym, val, global_env);
233→        return val;
234→    }
235→
236→    /* lambda */
237→    if (head == sym_lambda) {
238→        int params = car(args);
239→        int body = car(cdr(args));
240→        return make_closure(params, body, env);
241→    }
242→
243→    /* defmacro: (defmacro name (params) body) */
244→    if (head == sym_defmacro) {
245→        int name = car(args);
246→        int mparams = car(cdr(args));
247→        int mbody = car(cdr(cdr(args)));
248→        int mac = make_macro(mparams, mbody, env);
249→        global_env = env_extend(name, mac, global_env);
250→        return mac;
251→    }
252→
253→    /* begin */
254→    if (head == sym_begin) {
255→        int result = NIL_VAL;
256→        while (!IS_NIL(args)) {
257→            result = eval(car(args), env);
258→            args = cdr(args);
259→        }
260→        return result;
261→    }
262→
263→    /* Function call: eval head */
264→    int fn = eval(head, env);
265→
266→    /* Macro expansion: apply with unevaluated args, then eval result */
267→    if (IS_EXTENDED(fn)) {
268→        if (ext_type(fn) == ETYPE_MACRO) {
269→            int mac_env = env_bind(closure_params(fn), args, closure_env(fn));
270→            int expanded = eval(closure_body(fn), mac_env);
271→            return eval(expanded, env);
272→        }
273→    }
274→
275→    /* Evaluate arguments */
276→    int evaled_args = eval_list(args, env);
277→
278→    return apply_fn(fn, evaled_args);
279→}
280→
281→int apply_fn(int fn, int args) {
282→    if (IS_EXTENDED(fn)) {
283→        int fn_type = ext_type(fn);
284→        if (fn_type == ETYPE_CLOSURE) {
285→            int bound_env = env_bind(closure_params(fn), args, closure_env(fn));
286→            return eval(closure_body(fn), bound_env);
287→        }
288→        if (fn_type == ETYPE_PRIMITIVE) {
289→            int id = FIXNUM_VAL(ext_data(fn));
290→            return apply_primitive(id, args);
291→        }
292→    }
293→    puts_str("ERR:not-fn\n");
294→    return NIL_VAL;
295→}
