    puts_str("--- compiler output ---\n");
    compile_program(prog);
    puts_str("--- end compiler output ---\n");

    puts_str("compile ok\n");
}

int main() {
    heap_init();
    gc_init();
    symbol_init();
    eval_init();
    gc_enabled = 1;  /* enable GC after init */
    test_scaffold();
    test_reader();
    test_eval();
    test_gc();
    test_compile();
    return 0;
}

