                        oninput={on_input}
                        placeholder="(+ 1 2)"
                        spellcheck="false"
                    />
                    <div class="controls">
                        <button onclick={on_eval} disabled={self.running || !self.loaded}>
                            {"Eval"}
                        </button>
                        <span class="status">{ &self.status }</span>
                    </div>
                </div>

                <style>{r#"
